/**
 * Embedded assets for the academy certificate PDF.
 *
 * Extracted from the official certificate template (AYC-246). The font is
 * Source Sans 3 (SIL Open Font License), Google Fonts latin-subset variable
 * font covering weights 200-700. Assets are inlined as data URIs because the
 * certificate HTML is rendered in headless Chromium, which cannot load
 * external resources at runtime.
 */

export const AYUNIS_CORE_WORDMARK_DATA_URI =
  'data:image/jpeg;base64,';

export const AYC_MARK_DATA_URI =
  'data:image/jpeg;base64,';

export const SIGNATURE_DATA_URI =
  'data:image/png;base64,';

export const SOURCE_SANS_3_WOFF2_DATA_URI =
  'data:font/woff2;base64,';
